import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"11. Redundancy And Associated Entitlements","description":"","frontmatter":{"title":"11. Redundancy And Associated Entitlements","eba":"Doctors in Training 2022-2026","topics":["wages","employment","redundancy","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/consultation-disputes/11-redundancy-and-associated-entitlements.md","filePath":"ebas/doctors-in-training/consultation-disputes/11-redundancy-and-associated-entitlements.md"}'),a={name:"ebas/doctors-in-training/consultation-disputes/11-redundancy-and-associated-entitlements.md"};function i(s,e,c,p,l,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_11-redundancy-and-associated-entitlements" tabindex="-1">11. Redundancy And Associated Entitlements <a class="header-anchor" href="#_11-redundancy-and-associated-entitlements" aria-label="Permalink to &quot;11. Redundancy And Associated Entitlements&quot;">​</a></h1><p><strong>11.1</strong> Arrangement</p><p>This clause is arranged as follows:</p><p><strong>(a)</strong> Arrangement (subclause 11.1),</p><p><strong>(b)</strong> Definitions (subclause 11.2),</p><p><strong>(c)</strong> Redeployment (subclause 11.3),</p><p><strong>(d)</strong> Support to Affected Doctors (subclause 11.4),</p><p><strong>(e)</strong> Salary maintenance (subclause 11.5),</p><p><strong>(f)</strong> Relocation (subclause 11.6),</p><p><strong>(g)</strong> Employment terminates due to redundancy (subclause 11.7), and</p><p><strong>(h)</strong> Exception to application of Victorian Government’s policy with respect to severance pay (subclause 11.8).</p><p><strong>11.2</strong> Definitions</p><p><strong>(a)</strong> Affected Doctor for this clause 11 means a Doctor whose role will be redundant.</p><p><strong>(b)</strong> Comparable Role means an on-going role that:</p><p><strong>(i)</strong> is the same occupation as that of the Affected Doctor’s redundant position or, if not, is in an occupation acceptable to the Affected Doctor; and</p><p><strong>(ii)</strong> is any of the following:</p><p>A. in the same clinical specialty as that of the Affected Doctor’s former position;</p><p>B. in a clinical specialty acceptable to the Affected Doctor; or</p><p>C. a position that with the reasonable support described at subclause 11.3(g), the Affected Doctor could undertake; and</p><p><strong>(iii)</strong> is the same Classification / Pay Point as the Affected Doctor’s redundant position;</p><p><strong>(iv)</strong> takes into account the number of ordinary hours normally worked by the Affected Doctor;</p><p><strong>(v)</strong> is a Reasonable Distance from the Affected Doctor’s current work location;</p><p><strong>(vi)</strong> takes the Affected Doctor’s personal circumstances, including family responsibilities, into account; and</p><p><strong>(vii)</strong> takes account of health and safety considerations.</p><p><strong>(c)</strong> Consultation is as defined at <a href="/eba/ebas/doctors-in-training/consultation-disputes/10-consultation.html">clause 10</a> (Consultation) of this Agreement.</p><p><strong>(d)</strong> Continuity of Service at clause 11.8 means that the service of the Doctor is treated as unbroken and that the cap on the transfer of personal leave at subclause</p><p><strong>61.8</strong> does not apply. However, Continuity of Service is not broken where a Health Service pays out accrued annual leave or long service leave upon termination in accordance with this Agreement.</p><p><strong>(e)</strong> Classification / Pay Point for the purposes of this clause 11 means a weekly salary in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a> that is at least equal to or higher than the weekly salary in</p><p><strong>(f)</strong> Reasonable Distance means a distance that has regard to the Doctor’s original work location, current home address, capacity of the Doctor to travel, additional travelling time, effects on the personal circumstances of the Affected Doctor, including family commitments and responsibilities and other matters raised by the Doctor, or assistance provided by their Health Service.</p><p><strong>(g)</strong> Redeployment period means a period of 13 weeks from the time the Health Service notifies the Affected Doctor in writing that consultation under <a href="/eba/ebas/doctors-in-training/consultation-disputes/10-consultation.html">clause 10</a> is complete and that the redeployment period has begun.</p><p><strong>(h)</strong> Redundancy means the Health Service no longer requires the Affected Doctor’s job to be performed by anyone because of changes in the operational requirements of the Health Service’s enterprise.</p><p><strong>(i)</strong> Relocation means an Affected Doctor is required to move to a different campus as a result of an organisational change on either a temporary or permanent basis.</p><p><strong>(j)</strong> Salary maintenance means an amount representing the difference between what the Affected Doctor was normally paid immediately prior to the Affected Doctor’s role being made redundant and the amount paid in the Affected Doctor’s new role following redeployment.</p><p><strong>11.3</strong> Redeployment</p><p><strong>(a)</strong> An Affected Doctor whose role will be redundant will be considered for redeployment during the redeployment period.</p><p><strong>(b)</strong> Doctor to be advised in writing</p><p>The Affected Doctor must be advised in writing of:</p><p><strong>(i)</strong> the date the Affected Doctor’s role is to be redundant;</p><p><strong>(ii)</strong> details of the redeployment process;</p><p><strong>(iii)</strong> the reasonable support that will be provided in accordance with subclause 11.3(g); and</p><p><strong>(iv)</strong> the Affected Doctor’s rights and obligations.</p><p><strong>(c)</strong> Health Service obligations</p><p>The Health Service will:</p><p><strong>(i)</strong> make every effort to redeploy the Affected Doctor to a Comparable Role in terms of classification, grade and income, including appointing a case manager to provide the Affected Doctor with support and assistance; and</p><p><strong>(ii)</strong> take into account the personal circumstances of the Affected Doctor, including family commitments and responsibilities and</p><p><strong>(iii)</strong> where the Health Service is creating a new role/s substantially similar to the Affected Doctor’s redundant role; give priority to the redeployment of an Affected Doctor/s to the new position/s before considering applicants that are not Affected Doctors.</p><p>Example: The Health Service needs fewer Doctors to do particular work and roles are being restructured to take this into account. In a ‘spill and fill’, the Employer will consider the Affected Doctors for the new roles before other applicants.</p><p><strong>(d)</strong> Doctor obligations</p><p>The Doctor must actively participate in the redeployment process including:</p><p><strong>(i)</strong> identifying appropriate retraining needs;</p><p><strong>(ii)</strong> developing a resume / CV to assist in securing redeployment; and</p><p><strong>(iii)</strong> actively monitoring and exploring appropriate redeployment opportunities and working with the appointed case manager.</p><p><strong>(e)</strong> Rejecting a Comparable Role</p><p>Where an Affected Doctor rejects an offer of redeployment to a Comparable Role (as defined), the Affected Doctor may be ineligible for a departure package referred to at subclause 11.7.</p><p><strong>(f)</strong> Temporary alternative duties</p><p>An Affected Doctor awaiting redeployment may be transferred to temporary alternative duties within the same campus, or where part of the Doctor’s existing employment conditions (or by agreement) at another campus. Such temporary duties will be in accordance with the Affected Doctor’s skills, experience, clinical area and profession.</p><p><strong>(g)</strong> Support for redeployment</p><p>For an available role to be considered a Comparable Role, the Health Service must provide the reasonable support necessary for the Affected Doctor to perform the role which may include:</p><p><strong>(i)</strong> theory training relevant to the clinical area or environment of the role into which the Affected Doctor is to be redeployed;</p><p><strong>(ii)</strong> a defined period of up to 12 weeks in which the Affected Doctor works in a supernumerary capacity;</p><p><strong>(iii)</strong> support from educational staff in the clinical environment;</p><p><strong>(iv)</strong> a review at 12 weeks or earlier to determine what, if any, further training is required.</p><p><strong>(h)</strong> Where no redeployment available</p><p>If at any time during the redeployment period it is agreed that it is unlikely that the Affected Doctor will be successfully redeployed, the Affected Doctor may accept a redundancy package. Where this occurs, the Affected Doctor will be entitled to an additional payment of the lesser of 13 weeks or the remaining redeployment period.</p><p><strong>(i)</strong> Non-Comparable Role</p><p>An Affected Doctor may agree to be redeployed to a role that is not a Comparable Role.</p><p><strong>11.4</strong> Support to Affected Doctors</p><p>The Health Service will provide Affected Doctors whose position has been declared redundant with support and assistance which will include, where relevant:</p><p><strong>(a)</strong> counselling and support services;</p><p><strong>(b)</strong> retraining;</p><p><strong>(c)</strong> preparation of job applications;</p><p><strong>(d)</strong> interview coaching;</p><p><strong>(e)</strong> time off to attend job interviews; and</p><p><strong>(f)</strong> funding of independent financial advice for employees eligible to receive a separation package.</p><p>Other assistance may include but is not limited to career planning.</p><p><strong>11.5</strong> Salary Maintenance</p><p><strong>(a)</strong> Entitlement to salary maintenance</p><p>An Affected Doctor who is successfully redeployed will be entitled to salary maintenance where the Affected Doctor’s pay is reduced because the new role:</p><p><strong>(i)</strong> is a lower Classification / Pay Point;</p><p><strong>(ii)</strong> involves working fewer hours; and/or</p><p><strong>(iii)</strong> removes eligibility for penalties, loadings and the like.</p><p><strong>(b)</strong> Period of salary maintenance</p><p>Salary maintenance will be for a period of 52 weeks from the date the Affected Doctor is redeployed except where the Affected Doctor:</p><p><strong>(i)</strong> accepts another position within the salary maintenance period, and</p><p><strong>(ii)</strong> is paid in the other position an amount equal to or greater than the role that was made redundant.</p><p><strong>(c)</strong> Preservation of accrued leave</p><p>An Affected Doctor entitled to salary maintenance will have:</p><p><strong>(i)</strong> their long service leave and annual leave accruals preserved before redeployment. Specifically, the value of the leave immediately prior to redeployment will not be reduced as a result of redeployment; and</p><p><strong>(ii)</strong> their personal leave preserved in hours.</p><p><strong>11.6</strong> Relocation</p><p><strong>(a)</strong> Health Service to advise in writing of relocation</p><p>As soon as practicable but no less than seven (7) days after a decision is made by the Health Service to temporarily or permanently relocate an Affected Doctor, the Health Service will advise the Affected Doctor in writing of the decision, the proposed timing of the relocation and any other alternatives available to the Affected Doctor. In addition, the Health Service will:</p><p><strong>(i)</strong> ensure the relocation is a Reasonable Distance, unless otherwise agreed;</p><p><strong>(ii)</strong> ensure that the Affected Doctor is provided with information on the new location’s amenities, layout and local operations prior to the relocation, and</p><p><strong>(iii)</strong> consult with the Association regarding the content of such information.</p><p><strong>(b)</strong> Entitlement to relocation allowance</p><p>An Affected Doctor is entitled to relocation allowance where permanent or temporary relocation results in additional cost to the Affected Doctor for travel and/or other expenses.</p><p><strong>(c)</strong> Doctor to provide written estimate</p><p>The Affected Doctor must make written application to the Health Service with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months.</p><p><strong>(d)</strong> Payment</p><p><strong>(i)</strong> The Health Service will pay the Affected Doctor a relocation allowance up to $1900.00 based on the written estimate of the Affected Doctor referred to at (c) where the Health Service accepts that estimate represents the additional cost to the Affected Doctor. The allowance shall be paid as a lump sum.</p><p><strong>(ii)</strong> When considering the Affected Doctor’s estimate, the Health Service may have regard to the Reasonable Distance</p><p><strong>(iii)</strong> In the event of a dispute about the Affected Doctor’s estimate it will be resolved under <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> (Dispute Resolution).</p><p><strong>(e)</strong> Exceptions</p><p>An Affected Doctor is not entitled to the relocation allowance if the site or campus to which the Affected Doctor is being relocated is a location to which they can be expected to be deployed as part of their existing employment conditions.</p><p><strong>(f)</strong> Fixed term employees not excluded</p><p>An Affected Doctor on a fixed term contract who is relocated will be covered by the terms of this clause for the duration of the fixed term contract.</p><p><strong>11.7</strong> Employment terminates due to redundancy</p><p>The Victorian Government’s policy with respect to public sector redundancy and the entitlements upon termination of employment as a result of redundancy is set out in the Public</p><p>Sector Workplace Relations Policies 2015, as amended or replaced from time to time. The Victorian Government policy, as amended or replaced from time to time, applies to Doctors but does not form part of this Agreement.</p><p><strong>11.8</strong> Exception to application of Victorian Government’s policy with respect to severance pay</p><p><strong>(a)</strong> Where the Affected Doctor’s Health Service secures a Comparable Role (as defined) with another Health Service covered by this Agreement, which:</p><p><strong>(i)</strong> is within a Reasonable Distance of the work site of the redundant position; and</p><p><strong>(ii)</strong> provides Continuity of Service; and</p><p><strong>(iii)</strong> where the Comparable Role results in a loss of income, salary maintenance at subclause 11.5 will apply; and</p><p><strong>(iv)</strong> where relevant, consistent with the financial and other support provided to an internal redeployee;</p><p>the Doctor will be considered successfully redeployed as though the employment was with the same Health Service and no severance pay will apply.</p><p>Plain language terms: redundancy pay, retrenchment.</p>',118)])])}const f=t(a,[["render",i]]);export{g as __pageData,f as default};
